Here is a complete, single-file HTML solution using **Three.js**. This code generates a 3D scene with a ground plane, lighting, and a procedurally generated house (walls, roof, door, and windows).

You can save the code below as an `.html` file (e.g., `house.html`) and open it in any modern web browser.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>3D House Model</title>
    <style>
        body { margin: 0; overflow: hidden; background-color: #87CEEB; }
        canvas { display: block; }
        #info {
            position: absolute;
            top: 10px;
            width: 100%;
            text-align: center;
            color: white;
            font-family: sans-serif;
            font-weight: bold;
            text-shadow: 1px 1px 2px black;
            pointer-events: none;
        }
    </style>
</head>
<body>
    <div id="info">3D House Model (Click & Drag to Rotate)</div>

    <!-- Import Three.js from CDN -->
    <script type="importmap">
        {
            "imports": {
                "three": "https://unpkg.com/three@0.160.0/build/three.module.js",
                "three/addons/": "https://unpkg.com/three@0.160.0/examples/jsm/"
            }
        }
    </script>

    <script type="module">
        import * as THREE from 'three';
        import { OrbitControls } from 'three/addons/controls/OrbitControls.js';

        // --- 1. Scene Setup ---
        const scene = new THREE.Scene();
        scene.background = new THREE.Color(0x87CEEB); // Sky blue
        scene.fog = new THREE.Fog(0x87CEEB, 20, 100);

        const camera = new THREE.PerspectiveCamera(45, window.innerWidth / window.innerHeight, 0.1, 1000);
        camera.position.set(15, 10, 15);

        const renderer = new THREE.WebGLRenderer({ antialias: true });
        renderer.setSize(window.innerWidth, window.innerHeight);
        renderer.shadowMap.enabled = true; // Enable shadows
        document.body.appendChild(renderer.domElement);

        // --- 2. Lighting ---
        const ambientLight = new THREE.AmbientLight(0xffffff, 0.6);
        scene.add(ambientLight);

        const dirLight = new THREE.DirectionalLight(0xffffff, 1);
        dirLight.position.set(10, 20, 10);
        dirLight.castShadow = true;
        dirLight.shadow.mapSize.width = 2048;
        dirLight.shadow.mapSize.height = 2048;
        scene.add(dirLight);

        // --- 3. Environment ---
        // Ground
        const groundGeo = new THREE.PlaneGeometry(100, 100);
        const groundMat = new THREE.MeshStandardMaterial({ color: 0x4caf50 });
        const ground = new THREE.Mesh(groundGeo, groundMat);
        ground.rotation.x = -Math.PI / 2;
        ground.receiveShadow = true;
        scene.add(ground);

        // --- 4. House Construction ---
        const houseGroup = new THREE.Group();
        scene.add(houseGroup);

        // Materials
        const wallMat = new THREE.MeshStandardMaterial({ color: 0xffffff }); // White walls
        const roofMat = new THREE.MeshStandardMaterial({ color: 0x8b4513 }); // Brown roof
        const doorMat = new THREE.MeshStandardMaterial({ color: 0x3e2723 }); // Dark wood
        const windowMat = new THREE.MeshStandardMaterial({ color: 0x87CEEB, emissive: 0x87CEEB, emissiveIntensity: 0.2 });

        // Helper function to create walls
        function createWall(w, h, d, x, y, z, rotY = 0) {
            const geo = new THREE.BoxGeometry(w, h, d);
            const mesh = new THREE.Mesh(geo, wallMat);
            mesh.position.set(x, y, z);
            mesh.rotation.y = rotY;
            mesh.castShadow = true;
            mesh.receiveShadow = true;
            houseGroup.add(mesh);
            return mesh;
        }

        // Main Body
        createWall(6, 4, 6, 0, 2, 0);

        // Roof (Pyramid)
        const roofGeo = new THREE.ConeGeometry(5, 3, 4);
        const roof = new THREE.Mesh(roofGeo, roofMat);
        roof.position.set(0, 5.5, 0);
        roof.rotation.y = Math.PI / 4; // Rotate to align with walls
        roof.castShadow = true;
        houseGroup.add(roof);

        // Door
        const doorGeo = new THREE.BoxGeometry(1.5, 2.5, 0.2);
        const door = new THREE.Mesh(doorGeo, doorMat);
        door.position.set(0, 1.25, 3.1); // Slightly in front of wall
        door.castShadow = true;
        houseGroup.add(door);

        // Windows (Simple rectangles)
        function createWindow(x, y, z) {
            const geo = new THREE.BoxGeometry(1.2, 1.2, 0.1);
            const win = new THREE.Mesh(geo, windowMat);
            win.position.set(x, y, z);
            win.castShadow = true;
            houseGroup.add(win);
        }
        createWindow(1.8, 2.5, 0);
        createWindow(-1.8, 2.5, 0);

        // --- 5. Controls & Animation ---
        const controls = new OrbitControls(camera, renderer.domElement);
        controls.enableDamping = true;
        controls.target.set(0, 2, 0);

        // Handle Window Resize
        window.addEventListener('resize', onWindowResize, false);
        function onWindowResize() {
            camera.aspect = window.innerWidth / window.innerHeight;
            camera.updateProjectionMatrix();
            renderer.setSize(window.innerWidth, window.innerHeight);
        }

        // Render Loop
        function animate() {
            requestAnimationFrame(animate);
            controls.update();
            renderer.render(scene, camera);
        }
        animate();
    </script>
</body>
</html>
```

### How to use this:
1.  Copy the code block above.
2.  Create a new file on your computer named `house.html`.
3.  Paste the code into that file and save it.
4.  Double-click `house.html` to open it in your browser.

### Features included:
*   **Procedural Generation:** The house is built using geometric primitives (Boxes, Cones) grouped together.
*   **Lighting & Shadows:** Includes a directional light that casts realistic shadows on the ground and the house itself.
*   **Interactivity:** You can click and drag to rotate the camera, scroll to zoom, and right-click to pan (using `OrbitControls`).
*   **Responsive:** The canvas resizes automatically if you change the browser window size.
